CREATE FUNCTION crm_schema.set_case_number() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
      BEGIN
        IF NEW.case_number IS NULL OR NEW.case_number = '' THEN
          NEW.case_number := crm_schema.generate_case_number(NEW.loan_type, NEW.created_by);
        END IF;
        RETURN NEW;
      END;
      $$;


