    created_at timestamp without time zone DEFAULT CURRENT_TIMESTAMP,
    CONSTRAINT notes_visibility_check CHECK (((visibility)::text = ANY ((ARRAY['PRIVATE'::character varying, 'CASE'::character varying])::text[])))
);


